import React from "react";
import styles from './Header.module.scss';

// images
import logo from './../../assets/img/logo.svg';

const Header = () => {
  return(
    <div className={styles.header}>
      <div className={styles.headerContent}>
        <div className={styles.headerLogoBlock}>
          <img className={styles.logo} src={logo} alt="" />
          <h5 className={styles.logoTitle}>ТранспроектИнжиниринг</h5>
        </div>
        <div className={styles.headerNavBlock}>

          <li className={styles.navItem}>
            <a className={styles.navLink} href="">О компании</a>
          </li>

          <li className={styles.navItem}>
            <a className={styles.navLink} href="">Новости</a>
          </li>

          <li className={styles.navItem}>
            <a className={styles.navLink} href="">Объекты</a>
          </li>

          <li className={styles.navItem}>
            <a className={styles.navLink} href="">О компании</a>
          </li>

        </div>
      </div>
    </div>
  );
}

export default Header;
